            ContentBlock::ToolUse {
                id: "id1".to_string(),
                name: "Bash".to_string(),
                input: serde_json::Value::Null,
            },
        ];
        let filtered = filter_null_input_tool_use(blocks);
        assert_eq!(filtered.len(), 1);
        assert!(matches!(filtered[0], ContentBlock::Text { .. }));

